/* eslint-disable */
/**
 * Generate src/components/maps/leafletAssets.generated.ts from
 * node_modules/leaflet/dist/. Bundles Leaflet's JS + CSS as inline string
 * exports so the WebView template doesn't have to fetch them from a CDN
 * at runtime.
 *
 * Why a generated file rather than `require('leaflet/dist/leaflet.js')`:
 * Metro bundles `require()` of .js files as imported modules, not as raw
 * text. We need the raw text to inline into the WebView HTML. So we
 * pre-process the files into a string-exporting TypeScript module that
 * the bundler treats normally.
 *
 * Re-runs on every `npm install` (postinstall hook) so leaflet upgrades
 * pick up automatically.
 */
const fs = require('fs');
const path = require('path');

const ROOT = path.resolve(__dirname, '..');
const LEAFLET_DIR = path.join(ROOT, 'node_modules', 'leaflet', 'dist');
const OUT_FILE = path.join(
  ROOT,
  'src',
  'components',
  'maps',
  'leafletAssets.generated.ts',
);

function readFile(name) {
  const p = path.join(LEAFLET_DIR, name);
  if (!fs.existsSync(p)) {
    console.error(`[generate-leaflet-assets] Missing file: ${p}`);
    console.error(
      '[generate-leaflet-assets] Has `npm install leaflet` been run?',
    );
    process.exit(1);
  }
  return fs.readFileSync(p, 'utf8');
}

/**
 * Escape the content for embedding inside a TypeScript template literal.
 * Backticks, dollar-curly sequences, and backslashes need escaping; the
 * rest is fine.
 */
function escapeForTemplateLiteral(s) {
  return s
    .replace(/\\/g, '\\\\')
    .replace(/`/g, '\\`')
    .replace(/\$\{/g, '\\${');
}

const css = readFile('leaflet.css');
const js = readFile('leaflet.js');

const banner = `// AUTO-GENERATED by scripts/generate-leaflet-assets.js — do not edit by hand.
// Re-runs on \`npm install\` (postinstall hook). Edit the script, not this file.
//
// Source: node_modules/leaflet/dist/{leaflet.css,leaflet.js}
// Leaflet license: BSD-2-Clause (https://github.com/Leaflet/Leaflet)

/* eslint-disable */
`;

const out = `${banner}
export const LEAFLET_CSS = \`${escapeForTemplateLiteral(css)}\`;

export const LEAFLET_JS = \`${escapeForTemplateLiteral(js)}\`;
`;

fs.writeFileSync(OUT_FILE, out, 'utf8');
console.log(
  `[generate-leaflet-assets] Wrote ${OUT_FILE} (${(out.length / 1024).toFixed(1)} KB)`,
);
